/// <summary>
/// extension class for form datasource PurchTable, PurchLine
/// </summary>
[ExtensionOf(formdatasourcestr(PurchTable, PurchLine))]
internal final class ETG_PurchTable_PurchLineDS_Extension
{
}

Method.Source:
/// <summary>
/// update custom design for termo feature
/// </summary>
/// <returns>int</returns>
public int active()
{
    int ret = next active();

    if(ETGACFParameters::find().EnableAlternateItemPOandGRN == NoYes::Yes)
    {
        FormRun             formRun;
        FormDataSource      purchLine_ds;
        PurchLine           purchLineCurrentRecord;

        purchLine_ds           = any2Object(this) as FormDataSource;
        formRun                = purchLine_ds.formRun();
        purchLineCurrentRecord = purchLine_ds.cursor();
        formRun.design().controlName(formControlStr(PurchTable, ETGPurchRateCard)).enabled(purchLineCurrentRecord.canRateCardApply());
    }

    //CS - Abhinav - form control fields non editable 
    FormRun             formRun;
    FormDataSource      purchLine_ds;
    PurchLine           purchLineCurrentRecord;

    purchLine_ds           = any2Object(this) as FormDataSource;
    formRun                = purchLine_ds.formRun();
    purchLineCurrentRecord = purchLine_ds.cursor();
    PurchTable purchtable = PurchTable::find(purchLineCurrentRecord.PurchId);

    if(ETGCanadaparameters::find().EnableElevatorReceipt)
    {
        formRun.design().controlName(formControlStr(PurchTable, PurchLine_PurchPriceGrid)).allowEdit(!purchtable.ETGElevatorReceiptNumber);
        formRun.design().controlName(formControlStr(PurchTable, PurchLine_LineAmountGrid)).allowEdit(!purchtable.ETGElevatorReceiptNumber);
    }

    if(ETGcanadaparameters::find().EnableRateCardChanges && purchTable.ETGElevatorReceiptNumber && purchLineCurrentRecord.ETGRateCardApplied)
    {
        formRun.design().controlName(formControlStr(PurchTable, PurchLine_PurchQtyGrid)).allowEdit(false);
    }
    //CE

    return ret;
}
